// Valide le secret webhook et normalise les champs d'entrée
const secret = $input.first().json.headers?.['x-webhook-secret'];
if (secret !== $env.N8N_WEBHOOK_SECRET) {
  throw new Error('Unauthorized');
}

const body = $input.first().json.body;

const fromPhone = String(body.from_phone || '')
  .replace(/\s/g, '')
  .replace(/^00/, '+');

if (!fromPhone || !fromPhone.startsWith('+')) {
  throw new Error('from_phone invalide : format E.164 requis');
}

const message = String(body.message || '').trim();
if (!message) {
  throw new Error('message vide');
}

const fromName  = String(body.from_name  || 'Client').trim();
const channel   = ['sms','whatsapp','web'].includes(body.channel) ? body.channel : 'sms';
const history   = Array.isArray(body.conversation_history) ? body.conversation_history : [];

// Sépare first_name / last_name
const parts      = fromName.trim().split(' ');
const firstName  = parts[0] || fromName;
const lastName   = parts.slice(1).join(' ') || '';

return [{
  json: {
    fromPhone,
    fromName,
    firstName,
    lastName,
    message,
    channel,
    history
  }
}];

// Récupère les données des nœuds précédents
const normalized = $('Valider et normaliser').first().json;
const contactRaw = $input.first().json;

// contact peut être objet direct ou tableau selon Supabase
const contact = Array.isArray(contactRaw) ? contactRaw[0] : contactRaw;
const contactId = contact?.id || null;

// Reconstruit l'historique de conversation pour Claude
// Format attendu : [{ role: 'user'|'assistant', content: string }]
const history = (normalized.history || []).map(m => ({
  role:    m.role === 'assistant' ? 'assistant' : 'user',
  content: String(m.content)
}));

// Ajoute le message courant en dernier
const messages = [
  ...history,
  { role: 'user', content: normalized.message }
];

// System prompt avec shop_name injecté
const shopName = $env.NEXT_PUBLIC_SHOP_NAME || 'notre atelier';
const systemPrompt = `Tu es l'assistant virtuel de l'atelier de réparation "${shopName}". Tu reçois des messages de clients décrivant leurs appareils en panne.\n\nTon rôle :\n1. Analyser le message du client\n2. Extraire les informations nécessaires à la création d'un ticket de réparation\n3. Si des informations manquent, poser UNE seule question à la fois, dans cet ordre de priorité : type d'appareil → description du problème → marque → modèle\n4. Si tu as toutes les informations minimales (type + description), créer le ticket\n5. Si la demande est hors périmètre (pas une réparation électronique), rediriger poliment\n\nInformations à extraire :\n- device_type : smartphone | tablet | laptop | console | tv | appliance | other\n- device_brand : marque de l'appareil (optionnel)\n- device_model : modèle précis (optionnel)\n- issue_description : description du problème (minimum 10 mots)\n- urgency : low | normal | high\n\nRègles absolues :\n- Toujours répondre en français\n- Ne jamais inventer des informations non fournies par le client\n- Ne jamais promettre un prix ou un délai\n- Être chaleureux, professionnel, et concis (maximum 2 phrases par réponse)\n- Ne jamais mentionner que tu es une IA sauf si le client le demande explicitement\n\nFormat de ta réponse : JSON uniquement, sans texte avant ou après, sans backticks.\n\n{\n  "action": "create_ticket" | "ask_question" | "out_of_scope" | "unclear",\n  "confidence": 0.0,\n  "client_message_to_send": "message à envoyer au client",\n  "question_focus": "device_type | device_brand | device_model | issue_description | null",\n  "ticket_data": {\n    "device_type": "string | null",\n    "device_brand": "string | null",\n    "device_model": "string | null",\n    "issue_description": "string | null",\n    "urgency": "low | normal | high"\n  }\n}`;

return [{
  json: {
    fromPhone:  normalized.fromPhone,
    fromName:   normalized.fromName,
    channel:    normalized.channel,
    contactId,
    claudeBody: {
      model:      'claude-opus-4-5',
      max_tokens: 500,
      system:     systemPrompt,
      messages
    }
  }
}];

const prev   = $('Construire requête Claude').first().json;
const raw    = $input.first().json;

// Si le nœud précédent a échoué (continueOnFail)
if (raw.error) {
  return [{
    json: {
      ...prev,
      action: 'unclear',
      confidence: 0,
      client_message_to_send: 'Je suis momentanément indisponible. Nous vous recontacterons rapidement.',
      ticket_data: { device_type: null, device_brand: null, device_model: null, issue_description: null, urgency: 'normal' }
    }
  }];
}

// Extrait le texte brut retourné par Claude
let rawText = '';
try {
  rawText = raw.content[0].text.trim();
} catch {
  rawText = '';
}

// Parse le JSON retourné par Claude
// Claude peut parfois ajouter du texte parasite malgré les consignes
let parsed = null;
try {
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) parsed = JSON.parse(match[0]);
} catch {
  parsed = null;
}

if (!parsed || !['create_ticket','ask_question','out_of_scope','unclear'].includes(parsed.action)) {
  parsed = {
    action: 'unclear',
    confidence: 0,
    client_message_to_send: 'Je n\'ai pas bien compris votre demande. Pouvez-vous reformuler ?',
    question_focus: null,
    ticket_data: { device_type: null, device_brand: null, device_model: null, issue_description: null, urgency: 'normal' }
  };
}

return [{
  json: {
    fromPhone:  prev.fromPhone,
    fromName:   prev.fromName,
    channel:    prev.channel,
    contactId:  prev.contactId,
    action:     parsed.action,
    confidence: parsed.confidence || 0,
    clientMsg:  parsed.client_message_to_send || '',
    ticketData: parsed.ticket_data || {},
    questionFocus: parsed.question_focus || null
  }
}];

const parsed = $('Parser réponse Claude').first().json;
const ticketResult = $input.first().json;

// Récupère le tracking_token retourné par la RPC
const result = Array.isArray(ticketResult) ? ticketResult[0] : ticketResult;
const token  = result?.tracking_token || result?.data?.tracking_token || null;

const baseUrl    = $env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000';
const trackUrl   = token ? `${baseUrl}/track/${token}` : null;

let replyMsg = parsed.clientMsg || 'Votre demande a bien ete enregistree. Notre equipe prendra contact avec vous rapidement.';

if (trackUrl) {
  replyMsg = `Parfait ! Votre dossier de reparation a ete ouvert. Suivez l\'avancement ici : ${trackUrl}`;
}

return [{
  json: {
    fromPhone: parsed.fromPhone,
    channel:   parsed.channel,
    replyMsg,
    action:    'create_ticket',
    token
  }
}];

const parsed = $input.first().json;

return [{
  json: {
    fromPhone: parsed.fromPhone,
    channel:   parsed.channel,
    replyMsg:  parsed.clientMsg,
    action:    'ask_question'
  }
}];

const parsed = $input.first().json;

const shopName  = $env.NEXT_PUBLIC_SHOP_NAME  || 'notre atelier';
const shopPhone = $env.NEXT_PUBLIC_SHOP_PHONE || '';

const replyMsg = parsed.clientMsg ||
  `Je suis l'assistant de ${shopName} pour les reparations electroniques. Pour toute autre demande, appelez-nous${shopPhone ? ' au ' + shopPhone : ''}.`;

return [{
  json: {
    fromPhone: parsed.fromPhone,
    channel:   parsed.channel,
    replyMsg,
    action:    parsed.action
  }
}];
